import type { CategoryJobPageConfig } from './types';

export function getCategoryJobConfig(slug: string): CategoryJobPageConfig | undefined {
  return CATEGORY_JOBS_DATA.find(c => c.slug === slug);
}

export function getAllCategoryJobSlugs(): string[] {
  return CATEGORY_JOBS_DATA.map(c => c.slug);
}

